95	export interface Damage {
96	  itemType: string;
97	  amount: number;
98	}
99	
100	export interface Incident {
101	  cause: string;
102	  damages: Damage[];
103	}
104	
105	export interface ClaimResult {
106	  payout: number;
107	  remainingCap: number;
108	}
