110	const insuranceValueByType: Record<string, number> = {
111	  sword: 1000,
112	  amulet: 600,
113	  staff: 800,
114	  potion: 400,
115	  rune: 250,
116	  moonstone: 250,
117	};
118	
119	const CAP_MULTIPLIER = 2;
120	const DEDUCTIBLE = 100;
121	const HALF_REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
122	const HALF_REIMBURSEMENT_RATE = 0.5;
123	
124	function totalInsuranceValue(policy: QuoteResult): number {
125	  return policy.items.reduce((sum, item) => sum + insuranceValueByType[item.type], 0);
126	}
127	
128	function remainingCapFor(policy: QuoteResult): number {
129	  return policy.remainingCap ?? CAP_MULTIPLIER * totalInsuranceValue(policy);
130	}
131	
132	function assertNonNegativeDamage(damage: Damage): void {
133	  if (damage.amount < 0) {
134	    throw new Error(`Negative damage amount: ${damage.amount}`);
135	  }
136	}
137	
138	function reimbursedAmount(damage: Damage, policy: QuoteResult): number {
139	  assertNonNegativeDamage(damage);
140	  const damagedItem = policy.items.find((item) => item.type === damage.itemType);
141	  if (damagedItem === undefined) {
142	    throw new Error(`Claimed item not in policy: ${damage.itemType}`);
143	  }
144	  const halfReimbursementApplies =
145	    enchantmentLevel(damagedItem) >= HALF_REIMBURSEMENT_ENCHANTMENT_THRESHOLD;
146	  return halfReimbursementApplies
147	    ? damage.amount * HALF_REIMBURSEMENT_RATE
148	    : damage.amount;
149	}
150	
151	function payoutForDamage(damage: Damage, policy: QuoteResult): number {
152	  return reimbursedAmount(damage, policy) - DEDUCTIBLE;
153	}
154	
155	export function claim(policy: QuoteResult, incident: Incident): ClaimResult {
156	  const totalPayout = incident.damages.reduce(
157	    (total, damage) => total + payoutForDamage(damage, policy),
158	    0,
159	  );
160	  const desiredPayout = Math.floor(totalPayout);
161	  const remainingCapBefore = remainingCapFor(policy);
162	  const payout = Math.min(desiredPayout, remainingCapBefore);
163	  const remainingCap = remainingCapBefore - payout;
164	  policy.remainingCap = remainingCap;
165	  return { payout, remainingCap };
166	}
